FILES = {'src/frontend/command_center/modern/index.html': '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n  <title>Claire Syntalion — Operator Console</title>\n  <link rel="stylesheet" href="claire_operator_shell.css" />\n</head>\n<body>\n  <div id="claire-app" class="claire-app">\n    <aside class="claire-sidebar">\n      <div class="brand-block">\n        <div class="brand-kicker">Claire Syntalion</div>\n        <div class="brand-name">CLAIRE</div>\n\n        <div id="claire-search" class="search-shell">\n          <div class="search-box">\n            <input id="claire-search-input" type="search" autocomplete="off" spellcheck="false" placeholder="Ask Claire or search workspace…" />\n            <button id="claire-mic-button" class="mic-button" type="button" aria-label="Use microphone">\n              <span aria-hidden="true">◉</span>\n            </button>\n          </div>\n          <div id="claire-search-results" class="search-results"></div>\n        </div>\n      </div>\n\n      <div class="sidebar-status-grid">\n        <div class="mini-card">\n          <div class="mini-value">v17.62.7</div>\n          <div class="mini-label">Console</div>\n        </div>\n        <div class="mini-card">\n          <div class="mini-value">Live capable</div>\n          <div class="mini-label">Mode</div>\n        </div>\n        <div class="mini-card">\n          <div id="sidebar-route" class="mini-value">No run loaded</div>\n          <div class="mini-label">Active path</div>\n        </div>\n        <div class="mini-card">\n          <div id="sidebar-validation" class="mini-value">Unverified</div>\n          <div class="mini-label">Trust state</div>\n        </div>\n      </div>\n\n      <nav class="sidebar-nav" aria-label="Claire operator sections">\n        <a href="#command" class="nav-item active"><span>01</span> Command</a>\n        <a href="#brief" class="nav-item"><span>02</span> Intelligence Brief</a>\n        <a href="#decision" class="nav-item"><span>03</span> Decision Path</a>\n        <a href="#output" class="nav-item"><span>04</span> Output Review</a>\n        <a href="#trust" class="nav-item"><span>05</span> Trust & Evidence</a>\n        <a href="#continuity" class="nav-item"><span>06</span> Continuity</a>\n      </nav>\n    </aside>\n\n    <main class="claire-main">\n      <header class="topbar">\n        <div>\n          <h1>Claire Operator Console</h1>\n          <p>Command Claire, review active runs, inspect decisions, and verify outputs before reuse.</p>\n        </div>\n        <div class="top-pills">\n          <span class="top-pill green">Live capable</span>\n          <span class="top-pill cyan">Operator surface</span>\n          <span class="top-pill amber">Trust gated</span>\n        </div>\n      </header>\n\n      <div class="workspace-grid">\n        <section id="command" class="panel command-panel">\n          <div class="panel-header">\n            <div>\n              <div class="panel-kicker">Command</div>\n              <h2>Start Here</h2>\n              <p>Launch, refresh, or review Claire’s latest available operating state.</p>\n            </div>\n            <button id="refresh-runtime" class="primary-button" type="button">Refresh Claire State</button>\n          </div>\n\n          <div class="metric-grid">\n            <div class="metric-card">\n              <div class="metric-label">Current run</div>\n              <div id="metric-run" class="metric-value">No run loaded</div>\n              <div class="metric-note">Latest known Claire output</div>\n            </div>\n            <div class="metric-card">\n              <div class="metric-label">Operating path</div>\n              <div id="metric-route" class="metric-value">No path selected</div>\n              <div class="metric-note">Portfolio, breakthrough, design, acquisition, or blocked</div>\n            </div>\n            <div class="metric-card">\n              <div class="metric-label">Completion state</div>\n              <div id="metric-terminal" class="metric-value">Not complete</div>\n              <div class="metric-note">Meaningful terminal state required</div>\n            </div>\n            <div class="metric-card">\n              <div class="metric-label">Trust state</div>\n              <div id="metric-validation" class="metric-value">Unverified</div>\n              <div class="metric-note">Outputs remain gated until verified</div>\n            </div>\n          </div>\n        </section>\n\n        <aside id="brief" class="panel live-panel">\n          <div class="panel-kicker">Intelligence Brief</div>\n          <h2>What Claire Knows Right Now</h2>\n          <div id="live-feed" class="live-feed"></div>\n        </aside>\n      </div>\n\n      <section id="decision" class="panel">\n        <div class="panel-header">\n          <div>\n            <div class="panel-kicker">Decision Path</div>\n            <h2>Run Path, Stage Progress, and Decision State</h2>\n            <p>Operator view of where Claire is in the lifecycle and whether the result is ready for review.</p>\n          </div>\n          <span id="runtime-pill" class="status-pill amber">Not verified</span>\n        </div>\n\n        <div class="metric-grid six">\n          <div class="metric-card">\n            <div class="metric-label">Run</div>\n            <div id="stack-run" class="metric-value">No run loaded</div>\n          </div>\n          <div class="metric-card">\n            <div class="metric-label">Path</div>\n            <div id="stack-route" class="metric-value">No path selected</div>\n          </div>\n          <div class="metric-card">\n            <div class="metric-label">Completion</div>\n            <div id="stack-terminal" class="metric-value">Not complete</div>\n          </div>\n          <div class="metric-card">\n            <div class="metric-label">Lifecycle coverage</div>\n            <div id="stack-stages" class="metric-value">Not loaded</div>\n          </div>\n          <div class="metric-card">\n            <div class="metric-label">Evidence</div>\n            <div id="stack-evidence" class="metric-value">0 item(s)</div>\n          </div>\n          <div class="metric-card">\n            <div class="metric-label">Unsupported</div>\n            <div id="stack-unsupported" class="metric-value">0</div>\n          </div>\n        </div>\n      </section>\n\n      <div class="workspace-grid">\n        <section id="trust" class="panel">\n          <div class="panel-header">\n            <div>\n              <div class="panel-kicker">Trust & Evidence</div>\n              <h2>Can This Output Be Trusted?</h2>\n              <p>Claire’s result is not operator-ready until it passes verification and evidence checks.</p>\n            </div>\n            <span id="validation-pill" class="status-pill amber">Unverified</span>\n          </div>\n\n          <div class="metric-grid">\n            <div class="metric-card">\n              <div class="metric-label">Confidence score</div>\n              <div id="validation-score" class="metric-value">0/100</div>\n            </div>\n            <div class="metric-card">\n              <div class="metric-label">Review checks</div>\n              <div id="validation-checks" class="metric-value">0 pass / 0 warn / 0 fail</div>\n            </div>\n            <div class="metric-card wide">\n              <div class="metric-label">Operator message</div>\n              <div id="validation-message" class="metric-value small">No verified output loaded yet.</div>\n            </div>\n          </div>\n        </section>\n\n        <section id="continuity" class="panel purple">\n          <div class="panel-header">\n            <div>\n              <div class="panel-kicker purple-text">Continuity</div>\n              <h2>Can Claire Reuse This Result?</h2>\n              <p>Only verified outputs can become trusted continuity for future Claire reasoning.</p>\n            </div>\n            <span id="memory-pill" class="status-pill amber">Not ready</span>\n          </div>\n\n          <div class="metric-grid">\n            <div class="metric-card">\n              <div class="metric-label">Continuity status</div>\n              <div id="memory-status" class="metric-value">Not ready</div>\n            </div>\n            <div class="metric-card">\n              <div class="metric-label">Reuse eligibility</div>\n              <div id="memory-eligible" class="metric-value">Blocked</div>\n            </div>\n            <div class="metric-card">\n              <div class="metric-label">Feedback status</div>\n              <div id="feedback-status" class="metric-value">Not ready</div>\n            </div>\n            <div class="metric-card">\n              <div class="metric-label">Future-use permission</div>\n              <div id="feedback-allowed" class="metric-value">Blocked</div>\n            </div>\n            <div class="metric-card wide">\n              <div class="metric-label">Continuity reason</div>\n              <div id="memory-reason" class="metric-value small">Claire needs a verified output before continuity can be enabled.</div>\n            </div>\n          </div>\n        </section>\n      </div>\n\n      <section id="output" class="panel">\n        <div class="panel-header">\n          <div>\n            <div class="panel-kicker">Output Review</div>\n            <h2>Next Operator Actions</h2>\n            <p>Use this area to confirm what is missing before treating a run as finished.</p>\n          </div>\n        </div>\n        <div id="operator-actions" class="action-list"></div>\n      </section>\n\n      <details id="developer-diagnostics" class="diagnostics">\n        <summary>Developer diagnostics</summary>\n        <div class="command-list">\n          <code>python tools/claire_build_runtime_truth.py</code>\n          <code>python tools/claire_validate_runtime_truth.py</code>\n          <code>python tools/claire_build_verified_memory.py</code>\n          <code>python tools/claire_build_dashboard_search_index.py</code>\n        </div>\n      </details>\n\n      <footer class="proofbar">\n        <div><span>Run</span><strong id="proof-run">No run loaded</strong></div>\n        <div><span>Path</span><strong id="proof-route">No path selected</strong></div>\n        <div><span>Completion</span><strong id="proof-terminal">Not complete</strong></div>\n        <div><span>Stages</span><strong id="proof-stages">Not loaded</strong></div>\n        <div><span>Trust</span><strong id="proof-validation">Unverified</strong></div>\n        <div><span>Continuity</span><strong id="proof-memory">Not ready</strong></div>\n      </footer>\n    </main>\n  </div>\n\n  <script src="claire_operator_shell.js"></script>\n</body>\n</html>\n', 'src/frontend/command_center/modern/claire_operator_shell.css': ':root {\n  --bg: #070d19;\n  --panel: rgba(10, 17, 32, 0.92);\n  --border: rgba(0, 212, 255, 0.22);\n  --border-soft: rgba(148, 163, 184, 0.16);\n  --text: #dce8f7;\n  --muted: #94a3b8;\n  --cyan: #00d4ff;\n  --purple: #c084fc;\n  --green: #22c55e;\n  --amber: #f59e0b;\n  --red: #f87171;\n  --radius: 22px;\n  --font-display: Orbitron, "Segoe UI", system-ui, sans-serif;\n  --font: Inter, "Segoe UI", system-ui, sans-serif;\n}\n\n* { box-sizing: border-box; }\n\nhtml, body {\n  min-height: 100%;\n  margin: 0;\n  background: radial-gradient(circle at top right, rgba(79, 70, 229, 0.18), transparent 38%),\n              linear-gradient(135deg, #06121d, #070d19 45%, #070915);\n  color: var(--text);\n  font-family: var(--font);\n}\n\nbody { overflow-x: hidden; }\n\nbody::before {\n  content: "";\n  position: fixed;\n  inset: 0;\n  pointer-events: none;\n  background-image:\n    linear-gradient(rgba(0, 212, 255, 0.025) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(0, 212, 255, 0.025) 1px, transparent 1px);\n  background-size: 42px 42px;\n  opacity: .55;\n}\n\n.claire-app {\n  position: relative;\n  z-index: 1;\n  display: grid;\n  grid-template-columns: 430px minmax(0, 1fr);\n  min-height: 100vh;\n  gap: 20px;\n  padding: 22px;\n}\n\n.claire-sidebar {\n  position: sticky;\n  top: 22px;\n  align-self: start;\n  max-height: calc(100vh - 44px);\n  overflow-y: auto;\n  border: 1px solid var(--border);\n  border-radius: var(--radius);\n  background: rgba(8, 16, 30, 0.88);\n}\n\n.brand-block {\n  padding: 28px 28px 18px;\n  border-bottom: 1px solid rgba(148, 163, 184, 0.10);\n}\n\n.brand-kicker,\n.panel-kicker {\n  color: var(--cyan);\n  font-family: var(--font-display);\n  text-transform: uppercase;\n  letter-spacing: .18em;\n  font-size: 12px;\n  font-weight: 800;\n}\n\n.brand-name {\n  margin-top: 12px;\n  color: #e8fbff;\n  font-family: var(--font-display);\n  font-size: 45px;\n  letter-spacing: .22em;\n  font-weight: 900;\n}\n\n.search-shell {\n  margin-top: 20px;\n  position: relative;\n}\n\n.search-box {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  min-height: 48px;\n  padding: 8px 10px 8px 14px;\n  border: 1px solid rgba(0, 212, 255, 0.30);\n  border-radius: 18px;\n  background: rgba(2, 10, 20, 0.78);\n}\n\n.search-box input {\n  flex: 1;\n  min-width: 0;\n  border: 0;\n  outline: 0;\n  background: transparent;\n  color: #f8fafc;\n  font-size: 14px;\n}\n\n.search-box input::placeholder { color: #66758a; }\n\n.mic-button {\n  width: 36px;\n  height: 36px;\n  border-radius: 999px;\n  border: 1px solid rgba(0, 212, 255, 0.30);\n  color: var(--cyan);\n  background: rgba(0, 212, 255, 0.08);\n  cursor: pointer;\n}\n\n.mic-button.listening {\n  color: var(--green);\n  border-color: rgba(34, 197, 94, .7);\n}\n\n.mic-button[disabled] { opacity: .45; cursor: not-allowed; }\n\n.search-results {\n  display: none;\n  position: absolute;\n  left: 0;\n  right: 0;\n  top: calc(100% + 8px);\n  z-index: 1000;\n  max-height: 520px;\n  overflow: auto;\n  padding: 8px;\n  border: 1px solid rgba(0, 212, 255, 0.24);\n  border-radius: 18px;\n  background: rgba(3, 8, 18, 0.98);\n}\n\n.search-results.open { display: block; }\n\n.search-result {\n  width: 100%;\n  text-align: left;\n  border: 1px solid var(--border-soft);\n  border-radius: 14px;\n  margin: 6px 0;\n  padding: 10px 12px;\n  background: rgba(15, 23, 42, .52);\n  color: var(--text);\n  cursor: pointer;\n}\n\n.search-result:hover {\n  border-color: rgba(0, 212, 255, .46);\n  background: rgba(0, 212, 255, .08);\n}\n\n.search-result-title { font-weight: 800; font-size: 13px; }\n.search-result-meta { margin-top: 3px; color: #7dd3fc; font-size: 10px; letter-spacing: .06em; text-transform: uppercase; }\n.search-result-snippet { margin-top: 6px; color: var(--muted); font-size: 12px; line-height: 1.45; }\n\n.sidebar-status-grid {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 12px;\n  padding: 22px 28px;\n}\n\n.mini-card {\n  min-height: 82px;\n  padding: 14px;\n  border: 1px solid var(--border-soft);\n  border-radius: 16px;\n  background: rgba(15, 23, 42, 0.46);\n}\n\n.mini-value {\n  font-weight: 900;\n  color: #f8fafc;\n  word-break: break-word;\n}\n\n.mini-label {\n  margin-top: 7px;\n  color: var(--muted);\n  text-transform: uppercase;\n  letter-spacing: .16em;\n  font-size: 11px;\n}\n\n.sidebar-nav { padding: 12px 20px 24px; }\n\n.nav-item {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  min-height: 48px;\n  padding: 10px 14px;\n  color: #b8c6d8;\n  text-decoration: none;\n  border-radius: 14px;\n  font-weight: 800;\n}\n\n.nav-item span {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  min-width: 38px;\n  min-height: 28px;\n  border: 1px solid rgba(0, 212, 255, .28);\n  border-radius: 10px;\n  color: var(--cyan);\n  font-family: var(--font-display);\n  font-size: 11px;\n}\n\n.nav-item.active,\n.nav-item:hover {\n  background: rgba(0, 212, 255, 0.08);\n  color: #f8fafc;\n}\n\n.claire-main {\n  min-width: 0;\n  padding-bottom: 110px;\n}\n\n.topbar,\n.panel {\n  border: 1px solid var(--border);\n  border-radius: var(--radius);\n  background: var(--panel);\n}\n\n.topbar {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 16px;\n  padding: 20px 28px;\n  margin-bottom: 20px;\n}\n\n.topbar h1,\n.panel h2 {\n  margin: 0;\n  color: #eef7ff;\n  font-family: var(--font-display);\n  font-weight: 900;\n  line-height: 1.2;\n  letter-spacing: .06em;\n}\n\n.topbar h1 { font-size: clamp(22px, 2vw, 30px); }\n.panel h2 { font-size: clamp(20px, 1.7vw, 28px); }\n\n.topbar p,\n.panel p {\n  margin: 8px 0 0;\n  color: var(--muted);\n  line-height: 1.55;\n}\n\n.top-pills {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  justify-content: flex-end;\n}\n\n.top-pill,\n.status-pill {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  min-height: 34px;\n  padding: 8px 14px;\n  border-radius: 999px;\n  border: 1px solid var(--border-soft);\n  color: #cbd5e1;\n  background: rgba(148, 163, 184, 0.06);\n  font-weight: 900;\n  white-space: nowrap;\n}\n\n.green { color: var(--green); border-color: rgba(34, 197, 94, .35); }\n.cyan { color: var(--cyan); border-color: rgba(0, 212, 255, .35); }\n.amber { color: var(--amber); border-color: rgba(245, 158, 11, .35); }\n.red { color: var(--red); border-color: rgba(248, 113, 113, .35); }\n\n.workspace-grid {\n  display: grid;\n  grid-template-columns: minmax(0, 2fr) minmax(360px, 1fr);\n  gap: 20px;\n  margin-bottom: 20px;\n  align-items: start;\n}\n\n.panel {\n  position: relative;\n  display: block;\n  width: 100%;\n  height: auto;\n  min-height: 0;\n  overflow: visible;\n  padding: 28px;\n  margin-bottom: 20px;\n  background: linear-gradient(135deg, rgba(8, 15, 29, .94), rgba(11, 19, 36, .88));\n}\n\n.panel.purple {\n  border-color: rgba(192, 132, 252, .30);\n  background: linear-gradient(135deg, rgba(17, 10, 34, .94), rgba(22, 14, 39, .88));\n}\n\n.panel-header {\n  display: flex;\n  align-items: flex-start;\n  justify-content: space-between;\n  gap: 18px;\n  flex-wrap: wrap;\n  margin-bottom: 22px;\n}\n\n.purple-text { color: var(--purple); }\n\n.primary-button {\n  border: 1px solid rgba(0, 212, 255, .45);\n  border-radius: 18px;\n  background: rgba(0, 212, 255, .08);\n  color: #e8fbff;\n  padding: 15px 22px;\n  font-weight: 900;\n  font-size: 15px;\n  cursor: pointer;\n}\n\n.primary-button:hover { background: rgba(0, 212, 255, .14); }\n\n.metric-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));\n  gap: 14px;\n}\n\n.metric-grid.six { grid-template-columns: repeat(auto-fit, minmax(190px, 1fr)); }\n\n.metric-card {\n  min-height: 112px;\n  padding: 16px;\n  border: 1px solid var(--border-soft);\n  border-radius: 18px;\n  background: rgba(15, 23, 42, .50);\n  overflow-wrap: anywhere;\n}\n\n.metric-card.wide { grid-column: 1 / -1; }\n\n.metric-label {\n  color: var(--muted);\n  font-size: 11px;\n  letter-spacing: .13em;\n  text-transform: uppercase;\n  margin-bottom: 9px;\n}\n\n.metric-value {\n  color: #f8fafc;\n  font-size: 20px;\n  font-weight: 950;\n  line-height: 1.35;\n}\n\n.metric-value.small {\n  font-size: 16px;\n  font-weight: 800;\n  color: #d8e4f4;\n}\n\n.metric-note {\n  margin-top: 10px;\n  color: #9fb0c6;\n  font-size: 13px;\n  line-height: 1.45;\n}\n\n.live-panel {\n  max-height: calc(100vh - 180px);\n  overflow-y: auto;\n}\n\n.live-feed,\n.action-list {\n  display: grid;\n  gap: 12px;\n}\n\n.feed-card,\n.action-card {\n  padding: 14px;\n  border: 1px solid var(--border-soft);\n  border-radius: 16px;\n  background: rgba(15, 23, 42, .48);\n}\n\n.feed-title,\n.action-title {\n  color: #f8fafc;\n  font-weight: 900;\n  margin-bottom: 7px;\n}\n\n.feed-text,\n.action-text {\n  color: var(--muted);\n  line-height: 1.5;\n}\n\n.feed-time {\n  margin-top: 10px;\n  color: #718096;\n  font-size: 12px;\n}\n\n.diagnostics {\n  margin: 20px 0;\n  border: 1px solid rgba(148, 163, 184, .14);\n  border-radius: 16px;\n  background: rgba(2, 6, 23, .34);\n  padding: 14px 18px;\n}\n\n.diagnostics summary {\n  cursor: pointer;\n  color: var(--muted);\n  font-weight: 800;\n}\n\n.command-list {\n  display: grid;\n  gap: 10px;\n  margin-top: 14px;\n}\n\n.command-list code {\n  display: block;\n  padding: 14px;\n  border: 1px solid var(--border-soft);\n  border-radius: 14px;\n  background: rgba(2, 6, 23, .48);\n  color: #c7f9ff;\n  white-space: pre-wrap;\n  overflow-wrap: anywhere;\n}\n\n.proofbar {\n  position: sticky;\n  bottom: 16px;\n  z-index: 20;\n  display: grid;\n  grid-template-columns: repeat(6, minmax(0, 1fr));\n  border: 1px solid var(--border);\n  border-radius: 20px;\n  background: rgba(7, 14, 27, .96);\n  backdrop-filter: blur(14px);\n  overflow: hidden;\n}\n\n.proofbar div {\n  padding: 14px 16px;\n  border-right: 1px solid rgba(148, 163, 184, .12);\n}\n\n.proofbar div:last-child { border-right: 0; }\n\n.proofbar span {\n  display: block;\n  color: var(--muted);\n  text-transform: uppercase;\n  letter-spacing: .12em;\n  font-size: 10px;\n  margin-bottom: 6px;\n}\n\n.proofbar strong {\n  display: block;\n  color: #f8fafc;\n  font-size: 14px;\n  overflow-wrap: anywhere;\n}\n\n@media (max-width: 1320px) {\n  .claire-app { grid-template-columns: 360px minmax(0, 1fr); padding: 16px; }\n  .workspace-grid { grid-template-columns: 1fr; }\n  .live-panel { max-height: none; }\n}\n\n@media (max-width: 920px) {\n  .claire-app { grid-template-columns: 1fr; }\n  .claire-sidebar { position: relative; top: auto; max-height: none; }\n  .topbar { align-items: flex-start; flex-direction: column; }\n  .proofbar { position: relative; bottom: auto; grid-template-columns: 1fr 1fr; }\n}\n', 'src/frontend/command_center/modern/claire_operator_shell.js': '(function () {\n  "use strict";\n\n  const PATHS = {\n    runtime: [\n      "../../../exports/latest/dashboard_runtime_truth.json",\n      "exports/latest/dashboard_runtime_truth.json",\n      "runtime_truth_status.json",\n      "./runtime_truth_status.json"\n    ],\n    validation: [\n      "../../../exports/latest/validation_authority_report.json",\n      "exports/latest/validation_authority_report.json",\n      "validation_authority_status.json",\n      "./validation_authority_status.json"\n    ],\n    evidence: [\n      "../../../exports/latest/evidence_traceability_index.json",\n      "exports/latest/evidence_traceability_index.json",\n      "evidence_traceability_status.json",\n      "./evidence_traceability_status.json"\n    ],\n    memory: [\n      "../../../exports/latest/verified_memory_gate_report.json",\n      "exports/latest/verified_memory_gate_report.json",\n      "verified_memory_status.json",\n      "./verified_memory_status.json"\n    ],\n    feedback: [\n      "../../../exports/latest/recursive_feedback_gate_report.json",\n      "exports/latest/recursive_feedback_gate_report.json",\n      "recursive_feedback_status.json",\n      "./recursive_feedback_status.json"\n    ],\n    search: [\n      "dashboard_search_index.json",\n      "./dashboard_search_index.json",\n      "../../../exports/latest/dashboard_search_index.json",\n      "exports/latest/dashboard_search_index.json"\n    ],\n    registries: [\n      "dashboard_architecture_map.json",\n      "lifecycle_stage_registry.json",\n      "runtime_surface_registry.json",\n      "route_surface_registry.json",\n      "dashboard_search_contract.json",\n      "intelligence_command_contract.json"\n    ]\n  };\n\n  let searchDocs = [];\n\n  function $(id) { return document.getElementById(id); }\n  function normalize(value) { return String(value ?? "").replace(/\\s+/g, " ").trim(); }\n  function lower(value) { return normalize(value).toLowerCase(); }\n  function escapeHtml(value) {\n    return String(value ?? "")\n      .replace(/&/g, "&amp;").replace(/</g, "&lt;")\n      .replace(/>/g, "&gt;").replace(/"/g, "&quot;");\n  }\n\n  function first(obj, keys, fallback = "") {\n    if (!obj || typeof obj !== "object") return fallback;\n    for (const key of keys) {\n      const value = obj[key];\n      if (value !== undefined && value !== null && value !== "") return value;\n    }\n    return fallback;\n  }\n\n  function section(obj, key) {\n    const value = obj?.[key];\n    return value && typeof value === "object" && !Array.isArray(value) ? value : {};\n  }\n\n  function operatorStatus(value, kind) {\n    const raw = lower(value);\n    if (!raw || raw === "not_loaded") {\n      if (kind === "run") return "No run loaded";\n      if (kind === "route") return "No path selected";\n      if (kind === "terminal") return "Not complete";\n      if (kind === "memory") return "Not ready";\n      return "Unverified";\n    }\n    const map = {\n      "not_generated": kind === "memory" ? "Not ready" : "Unverified",\n      "missing": "Not complete",\n      "blocked": "Blocked",\n      "failed": "Failed",\n      "fail": "Failed",\n      "warning": "Needs review",\n      "pass": "Verified",\n      "passed": "Verified",\n      "eligible": "Eligible",\n      "allowed": "Allowed",\n      "portfolio_action_ready": "Portfolio action ready",\n      "portfolio_optimization_ready": "Portfolio optimization ready",\n      "discovery_ready": "Discovery ready",\n      "breakthrough_classified": "Breakthrough classified",\n      "advancement_path_selected": "Advancement path selected",\n      "design_output_ready": "Design output ready",\n      "acquisition_ready": "Acquisition ready",\n      "acquisition_package_ready": "Acquisition package ready",\n      "final_package_ready": "Final package ready",\n      "insufficient_data": "Insufficient data",\n      "max_iterations_reached": "Max iterations reached"\n    };\n    return map[raw] || String(value).replace(/_/g, " ");\n  }\n\n  function technicalValue(value, fallback) {\n    return value === undefined || value === null || value === "" ? fallback : value;\n  }\n\n  async function fetchJson(path) {\n    try {\n      const response = await fetch(path, { cache: "no-store" });\n      if (!response.ok) return null;\n      return await response.json();\n    } catch (_) { return null; }\n  }\n\n  async function fetchFirst(paths) {\n    for (const path of paths) {\n      const json = await fetchJson(path);\n      if (json) return { path, json };\n    }\n    return { path: "", json: null };\n  }\n\n  function flattenJson(value, prefix = "") {\n    const rows = [];\n    function walk(node, path) {\n      if (node === null || node === undefined) return;\n      if (Array.isArray(node)) {\n        node.forEach((item, index) => walk(item, `${path}[${index}]`));\n        return;\n      }\n      if (typeof node === "object") {\n        Object.entries(node).forEach(([key, item]) => walk(item, path ? `${path}.${key}` : key));\n        return;\n      }\n      rows.push(`${path}: ${String(node)}`);\n    }\n    walk(value, prefix);\n    return rows.join("\\n");\n  }\n\n  function setText(id, value) {\n    const node = $(id);\n    if (node) node.textContent = value ?? "";\n  }\n\n  function statusClass(status) {\n    const s = lower(status);\n    if (["verified", "pass", "passed", "eligible", "allowed", "loaded"].includes(s)) return "green";\n    if (["failed", "fail", "blocked"].includes(s)) return "red";\n    if (["not ready", "unverified", "not_generated", "not complete", "no run loaded", "no path selected", "needs review"].includes(s)) return "amber";\n    return "cyan";\n  }\n\n  function applyPill(id, value) {\n    const node = $(id);\n    if (!node) return;\n    node.textContent = value;\n    node.className = `status-pill ${statusClass(value)}`;\n  }\n\n  function feed(title, text, version = "") {\n    const now = new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" });\n    return `\n      <div class="feed-card">\n        <div class="feed-title">${escapeHtml(title)}</div>\n        <div class="feed-text">${escapeHtml(text)}</div>\n        ${version ? `<div class="feed-time">${escapeHtml(version)}</div>` : ""}\n        <div class="feed-time">${escapeHtml(now)}</div>\n      </div>\n    `;\n  }\n\n  function action(title, text) {\n    return `\n      <div class="action-card">\n        <div class="action-title">${escapeHtml(title)}</div>\n        <div class="action-text">${escapeHtml(text)}</div>\n      </div>\n    `;\n  }\n\n  async function loadTruth() {\n    const runtime = await fetchFirst(PATHS.runtime);\n    const validation = await fetchFirst(PATHS.validation);\n    const evidence = await fetchFirst(PATHS.evidence);\n    const memory = await fetchFirst(PATHS.memory);\n    const feedback = await fetchFirst(PATHS.feedback);\n\n    const r = runtime.json || {};\n    const run = section(r, "run_truth");\n    const route = section(r, "route_truth");\n    const terminal = section(r, "terminal_truth");\n    const stage = section(r, "stage_truth");\n    const validationJson = validation.json || {};\n    const evidenceJson = evidence.json || {};\n    const memoryJson = memory.json || {};\n    const feedbackJson = feedback.json || {};\n\n    const rawRunId = first(validationJson, ["run_id"], first(run, ["run_id", "id"], first(r, ["run_id"], "")));\n    const rawRoute = first(validationJson, ["route_selected"], first(route, ["route_selected", "selected_route"], first(run, ["selected_route"], "")));\n    const rawTerminal = first(validationJson, ["terminal_state"], first(terminal, ["terminal_state", "state"], first(run, ["terminal_state"], "")));\n    const rawValidation = first(validationJson, ["validation_authority_status", "validation_status"], "");\n    const rawMemory = first(memoryJson, ["memory_status"], "");\n    const stages = first(stage, ["stages_total", "total_stages"], Array.isArray(stage.stages) ? String(stage.stages.length) : "Not loaded");\n\n    const runId = rawRunId || "No run loaded";\n    const routeLabel = operatorStatus(rawRoute, "route");\n    const terminalLabel = operatorStatus(rawTerminal, "terminal");\n    const validationLabel = operatorStatus(rawValidation, "validation");\n    const memoryLabel = operatorStatus(rawMemory, "memory");\n\n    const validationScore = first(validationJson, ["validation_score"], 0);\n    const checks = `${first(validationJson, ["checks_passed"], 0)} pass / ${first(validationJson, ["checks_warning"], 0)} warn / ${first(validationJson, ["checks_failed"], 0)} fail`;\n    const evidenceCount = first(evidenceJson, ["evidence_count"], first(validationJson.evidence_summary || {}, ["evidence_count"], 0));\n    const unsupportedCount = first(evidenceJson, ["unsupported_count"], first(validationJson.evidence_summary || {}, ["unsupported_count"], 0));\n    const memoryEligible = first(memoryJson, ["memory_eligible"], false) ? "Eligible" : "Blocked";\n    const feedbackStatus = operatorStatus(first(feedbackJson, ["feedback_status"], ""), "memory");\n    const feedbackAllowed = first(feedbackJson, ["recursive_feedback_allowed"], false) ? "Allowed" : "Blocked";\n\n    setText("sidebar-route", routeLabel);\n    setText("sidebar-validation", validationLabel);\n    setText("metric-run", runId);\n    setText("metric-route", routeLabel);\n    setText("metric-terminal", terminalLabel);\n    setText("metric-validation", validationLabel);\n\n    setText("stack-run", runId);\n    setText("stack-route", routeLabel);\n    setText("stack-terminal", terminalLabel);\n    setText("stack-stages", stages);\n    setText("stack-evidence", `${evidenceCount} item(s)`);\n    setText("stack-unsupported", unsupportedCount);\n\n    setText("validation-score", `${validationScore}/100`);\n    setText("validation-checks", checks);\n    setText("validation-message", validationJson.blocking_failures?.[0]?.details || validationJson.message || "No verified output loaded yet.");\n\n    setText("memory-status", memoryLabel);\n    setText("memory-eligible", memoryEligible);\n    setText("feedback-status", feedbackStatus);\n    setText("feedback-allowed", feedbackAllowed);\n    setText("memory-reason", memoryJson.memory_reasons?.[0] || feedbackJson.feedback_reasons?.[0] || "Claire needs a verified output before continuity can be enabled.");\n\n    setText("proof-run", runId);\n    setText("proof-route", routeLabel);\n    setText("proof-terminal", terminalLabel);\n    setText("proof-stages", stages);\n    setText("proof-validation", validationLabel);\n    setText("proof-memory", memoryLabel);\n\n    applyPill("runtime-pill", validationLabel);\n    applyPill("validation-pill", validationLabel);\n    applyPill("memory-pill", memoryLabel);\n\n    const live = $("live-feed");\n    if (live) {\n      const items = [];\n      if (!runtime.json) {\n        items.push(feed("No run loaded", "Claire has not loaded a real run output yet. The console is intentionally not inventing a result.", "operator"));\n      } else {\n        items.push(feed("Run loaded", `Current run: ${runId}. Operating path: ${routeLabel}. Completion: ${terminalLabel}.`, "operator"));\n      }\n      if (!validation.json || validationLabel === "Unverified") {\n        items.push(feed("Output not verified", "Run verification after Claire produces output before treating the result as trusted.", "trust"));\n      }\n      if (!memory.json || memoryLabel === "Not ready") {\n        items.push(feed("Continuity not enabled", "Claire will not reuse this result until it is verified and continuity is allowed.", "continuity"));\n      }\n      live.innerHTML = items.join("");\n    }\n\n    const actions = $("operator-actions");\n    if (actions) {\n      const todo = [];\n      if (!runtime.json) todo.push(action("Load or generate a run", "Claire needs a real output file before the operator console can show decisions or results."));\n      if (!validation.json) todo.push(action("Verify the result", "Run the verification step after a real run exists. Until then, trust state remains unverified."));\n      if (!memory.json) todo.push(action("Enable continuity only after verification", "Continuity stays blocked until the result is verified and eligible for future reuse."));\n      if (!todo.length) todo.push(action("Review output", "Claire has loaded the available run, trust, and continuity data. Review the result before acting."));\n      actions.innerHTML = todo.join("");\n    }\n  }\n\n  function addDoc(doc) {\n    const key = `${doc.type}:${doc.path}:${doc.title}`;\n    if (searchDocs.some((d) => `${d.type}:${d.path}:${d.title}` === key)) return;\n    searchDocs.push(doc);\n  }\n\n  async function buildSearchDocs() {\n    searchDocs = [];\n    document.querySelectorAll("section, aside, header, footer, details").forEach((node, index) => {\n      const text = normalize(node.innerText || node.textContent || "");\n      if (!text || text.length < 18) return;\n      if (!node.id) node.id = `operator-search-section-${index}`;\n      const title = normalize(node.querySelector("h1,h2,h3,.panel-kicker,summary")?.textContent || node.id);\n      addDoc({ type: "workspace", title, path: `#${node.id}`, text, targetId: node.id });\n    });\n\n    for (const group of Object.values(PATHS)) {\n      for (const path of group) {\n        const json = await fetchJson(path);\n        if (!json) continue;\n        if (json.schema === "claire.dashboard_intelligence_index.v1" && Array.isArray(json.documents)) {\n          json.documents.forEach((doc) => {\n            if (doc.status && doc.status !== "indexed") return;\n            addDoc({ type: "index", title: doc.title || doc.path || path, path: doc.path || path, text: doc.text || (doc.terms || []).join(" "), json: doc });\n          });\n        }\n        addDoc({ type: "local data", title: path.split("/").pop() || path, path, text: flattenJson(json), json });\n      }\n    }\n  }\n\n  function search(query) {\n    const parts = lower(query).split(" ").filter(Boolean);\n    if (!parts.length) return [];\n    return searchDocs.map((doc) => {\n      const hay = `${doc.title}\\n${doc.path}\\n${doc.text}`.toLowerCase();\n      let score = 0;\n      parts.forEach((p) => {\n        if (doc.title.toLowerCase().includes(p)) score += 12;\n        if (doc.path.toLowerCase().includes(p)) score += 6;\n        score += Math.min(hay.split(p).length - 1, 12);\n      });\n      return { doc, score };\n    }).filter((x) => x.score > 0).sort((a, b) => b.score - a.score).slice(0, 10);\n  }\n\n  function snippet(text, query) {\n    const clean = normalize(text);\n    const parts = lower(query).split(" ").filter(Boolean);\n    const hay = clean.toLowerCase();\n    let idx = -1;\n    for (const p of parts) {\n      idx = hay.indexOf(p);\n      if (idx >= 0) break;\n    }\n    if (idx < 0) return clean.slice(0, 220);\n    const start = Math.max(0, idx - 80);\n    const end = Math.min(clean.length, idx + 180);\n    return `${start > 0 ? "…" : ""}${clean.slice(start, end)}${end < clean.length ? "…" : ""}`;\n  }\n\n  function setupSearch() {\n    const input = $("claire-search-input");\n    const results = $("claire-search-results");\n    if (!input || !results) return;\n\n    input.addEventListener("input", () => {\n      const query = input.value.trim();\n      if (!query) {\n        results.classList.remove("open");\n        results.innerHTML = "";\n        return;\n      }\n      const matches = search(query);\n      if (!matches.length) {\n        results.classList.add("open");\n        results.innerHTML = `<div class="search-result-snippet" style="padding:12px;">No local matches. Claire is searching only loaded workspace and local truth data.</div>`;\n        return;\n      }\n      results.classList.add("open");\n      results.innerHTML = matches.map(({ doc }) => `\n        <button class="search-result" type="button">\n          <div class="search-result-title">${escapeHtml(doc.title)}</div>\n          <div class="search-result-meta">${escapeHtml(doc.type)} · ${escapeHtml(doc.path)}</div>\n          <div class="search-result-snippet">${escapeHtml(snippet(doc.text, query))}</div>\n        </button>\n      `).join("");\n\n      Array.from(results.querySelectorAll(".search-result")).forEach((button, index) => {\n        button.addEventListener("click", () => {\n          const doc = matches[index].doc;\n          results.classList.remove("open");\n          if (doc.targetId) {\n            const target = document.getElementById(doc.targetId);\n            if (target) target.scrollIntoView({ behavior: "smooth", block: "start" });\n          }\n        });\n      });\n    });\n\n    document.addEventListener("keydown", (event) => {\n      if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "k") {\n        event.preventDefault();\n        input.focus();\n        input.select();\n      }\n    });\n\n    document.addEventListener("click", (event) => {\n      if (!$("claire-search")?.contains(event.target)) results.classList.remove("open");\n    });\n  }\n\n  function setupMic() {\n    const button = $("claire-mic-button");\n    const input = $("claire-search-input");\n    if (!button || !input) return;\n    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;\n    if (!SpeechRecognition) {\n      button.disabled = true;\n      button.title = "Microphone search is not supported in this browser.";\n      return;\n    }\n    const recognition = new SpeechRecognition();\n    recognition.continuous = false;\n    recognition.interimResults = false;\n    recognition.lang = navigator.language || "en-US";\n    recognition.onstart = () => button.classList.add("listening");\n    recognition.onend = () => button.classList.remove("listening");\n    recognition.onerror = () => button.classList.remove("listening");\n    recognition.onresult = (event) => {\n      const transcript = Array.from(event.results || []).map((r) => r[0]?.transcript || "").join(" ").trim();\n      if (transcript) {\n        input.value = transcript;\n        input.dispatchEvent(new Event("input", { bubbles: true }));\n        input.focus();\n      }\n    };\n    button.addEventListener("click", () => {\n      try { recognition.start(); } catch (_) {}\n    });\n  }\n\n  function setupNav() {\n    const links = document.querySelectorAll(".nav-item");\n    links.forEach((link) => {\n      link.addEventListener("click", () => {\n        links.forEach((other) => other.classList.remove("active"));\n        link.classList.add("active");\n      });\n    });\n  }\n\n  async function boot() {\n    setupSearch();\n    setupMic();\n    setupNav();\n    await loadTruth();\n    await buildSearchDocs();\n\n    const refresh = $("refresh-runtime");\n    if (refresh) {\n      refresh.addEventListener("click", async () => {\n        refresh.textContent = "Refreshing…";\n        await loadTruth();\n        await buildSearchDocs();\n        refresh.textContent = "Refresh Claire State";\n      });\n    }\n  }\n\n  if (document.readyState === "loading") {\n    document.addEventListener("DOMContentLoaded", boot);\n  } else {\n    boot();\n  }\n})();\n', 'docs/dashboard/v17.62.7_operator_surface_conversion.md': '# Claire v17.62.7 — Operator Surface Conversion\n\n## Purpose\n\nv17.62.6 consolidated the shell, but it still exposed developer-oriented wording and surfaces. v17.62.7 converts the dashboard from developer language into operator-facing language.\n\n## Changes\n\n- Header changed from runtime/developer terminology to "Claire Operator Console".\n- "Runtime Truth Stack" becomes "Decision Path".\n- "Validation Authority" becomes "Trust & Evidence".\n- "Verified Memory + Recursive Feedback" becomes "Continuity".\n- Technical commands are moved into a collapsed Developer diagnostics section.\n- Search placeholder becomes "Ask Claire or search workspace".\n- Status labels become operator-friendly:\n  - not_loaded → No run loaded\n  - route not loaded → No path selected\n  - missing terminal → Not complete\n  - not_generated validation → Unverified\n  - memory not generated → Not ready\n\n## Scope\n\nNo backend logic changed.\nNo runtime logic changed.\nNo validation logic changed.\nNo memory logic changed.\nThis is a dashboard operator-surface conversion.\n', 'docs/update_packs/v17.62.7_operator_surface_pack.md': '# v17.62.7 Operator Surface Update Pack\n\n## Architecture section covered\n\n- Operator dashboard surface\n- Command\n- Intelligence brief\n- Decision path\n- Output review\n- Trust & evidence\n- Continuity\n\n## Verification\n\nAfter install:\n\n1. Hard refresh with Ctrl+F5.\n2. Confirm dashboard says "Claire Operator Console".\n3. Confirm no main panel says "Runtime Truth Stack".\n4. Confirm no main panel says "Developer" except collapsed Developer diagnostics.\n5. Confirm statuses are operator-friendly.\n6. Confirm search remains in the left Claire identity area with the mic button.\n', 'data/build_manifests/v17.62.7_operator_surface_manifest.json': '{\n  "version": "17.62.7",\n  "name": "Operator Surface Conversion",\n  "build_type": "dashboard_operator_surface",\n  "purpose": "Convert the clean dashboard shell from developer-facing terminology to operator-facing surfaces.",\n  "installed_files": [\n    "docs/dashboard/v17.62.7_operator_surface_conversion.md",\n    "docs/update_packs/v17.62.7_operator_surface_pack.md",\n    "src/frontend/command_center/modern/claire_operator_shell.css",\n    "src/frontend/command_center/modern/claire_operator_shell.js",\n    "src/frontend/command_center/modern/index.html"\n  ],\n  "replaces": [\n    "src/frontend/command_center/modern/index.html",\n    "src/frontend/command_center/modern/claire_operator_shell.css",\n    "src/frontend/command_center/modern/claire_operator_shell.js"\n  ],\n  "safety": {\n    "rollback_backups": true,\n    "launcher_path_preserved": "src/frontend/command_center/modern/index.html",\n    "runtime_logic_unchanged": true,\n    "validation_logic_unchanged": true,\n    "memory_logic_unchanged": true,\n    "no_fake_data": true\n  }\n}\n'}

def utc_stamp() -> str:
    return datetime.utcnow().strftime("%Y%m%d_%H%M%S")

def project_root() -> Path:
    return Path.cwd().resolve()

def backup_existing(root: Path, relative_path: str, backup_root: Path) -> None:
    target = root / relative_path
    if not target.exists():
        return
    backup_path = backup_root / relative_path
    backup_path.parent.mkdir(parents=True, exist_ok=True)
    if target.is_file():
        shutil.copy2(target, backup_path)
    elif target.is_dir():
        if backup_path.exists():
            shutil.rmtree(backup_path)
        shutil.copytree(target, backup_path)

def write_text(root: Path, relative_path: str, content: str, backup_root: Path) -> None:
    target = root / relative_path
    backup_existing(root, relative_path, backup_root)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")

def write_install_record(root: Path, backup_root: Path) -> None:
    record = {
        "version": VERSION,
        "build_name": BUILD_NAME,
        "installed_at_utc": datetime.utcnow().isoformat() + "Z",
        "project_root": str(root),
        "backup_root": str(backup_root),
        "files_written": sorted(FILES.keys()),
        "notes": [
            "Converted main dashboard surfaces from developer-facing terms to operator-facing terms.",
            "Developer diagnostics moved to collapsed section.",
            "Runtime, validation, and memory logic unchanged.",
            "Dashboard remains honest: no fake runtime data."
        ]
    }
    record_path = root / "data" / "build_manifests" / "v17.62.7_install_record.json"
    record_path.parent.mkdir(parents=True, exist_ok=True)
    record_path.write_text(json.dumps(record, indent=2) + "\n", encoding="utf-8")

def main() -> None:
    root = project_root()
    backup_root = root / "backups" / f"claire_v17_62_7_{utc_stamp()}"
    backup_root.mkdir(parents=True, exist_ok=True)

    for relative_path, content in FILES.items():
        write_text(root, relative_path, content, backup_root)

    write_install_record(root, backup_root)

    print("=" * 72)
    print(f"Claire v{VERSION} installed: {BUILD_NAME}")
    print("=" * 72)
    print(f"Project root: {root}")
    print(f"Backups:      {backup_root}")
    print("")
    print("Converted dashboard from developer surfaces to operator surfaces.")
    print("")
    print("Hard refresh the dashboard with Ctrl+F5.")
    print("=" * 72)

if __name__ == "__main__":
    main()
